problems.solution:
n = int(input())
arr = list(map(int, input().split()))
target = int(input())

mp = {}
for i, num in enumerate(arr):
    if target - num in mp:
        print(mp[target - num], i)
        break
    mp[num] = i

s = input().strip()
stack = []
mp = {')': '(', ']': '[', '}': '{'}

valid = True
for c in s:
    if c in "([{":
        stack.append(c)
    else:
        if not stack or stack[-1] != mp[c]:
            valid = False
            break
        stack.pop()

print("true" if valid and not stack else "false")

n = int(input())
intervals = [tuple(map(int, input().split())) for _ in range(n)]

intervals.sort()
merged = [intervals[0]]

for start, end in intervals[1:]:
    last_start, last_end = merged[-1]
    if start <= last_end:
        merged[-1] = (last_start, max(last_end, end))
    else:
        merged.append((start, end))

for s, e in merged:
    print(s, e)
